return [
  {
    hostname: $json.stdout.trim(),
    raw_commands: {
      hostname: {
        command: "hostname",
        stdout: $json.stdout,
        stderr: $json.stderr,
        exit_code: $json.code,
        timestamp: new Date().toISOString()
      }
    }
  }
];

return [
  {
    os_info: $json.stdout,
    raw_commands: {
      uname: {
        command: "uname -a",
        stdout: $json.stdout,
        stderr: $json.stderr,
        exit_code: $json.code,
        timestamp: new Date().toISOString()
      }
    }
  }
];

const output = $json.stdout;

const ips = [...output.matchAll(/inet\s(\d+\.\d+\.\d+\.\d+)/g)]
  .map(m => m[1])
  .filter(ip => ip !== "127.0.0.1");

return [
  {
    network: {
      ips
    },
    raw_commands: {
      ip_addr: {
        command: "ip addr",
        stdout: $json.stdout,
        stdder: $json.stdder,
        exit_code: $json.code,
        timestamp: new Date().toISOString()
      }
    }  
  }
];

function randomInt(min, max) {
  return Math.floor(Math.random() * (max - min + 1)) + min;
}

// Hash simple compatible con sandbox n8n
function simpleHash(str) {
  let hash = 0;
  if (!str) return 0;

  for (let i = 0; i < str.length; i++) {
    hash = ((hash << 5) - hash) + str.charCodeAt(i);
    hash |= 0;
  }

  return Math.abs(hash);
}

return items.map(item => {

  const hostname = item.json.hostname || "unknown";
  const osInfo = item.json.os_info || "unknown";
  const rawCommands = item.json.raw_commands || {};
  const network = item.json.network || {};

  // ----- host_id -----
  const hostId = simpleHash(hostname + osInfo);

  // ----- snapshot_status -----
  const commands = Object.values(rawCommands);

  let snapshotStatus = "complete";

  if (commands.length === 0) {
    snapshotStatus = "failed";
  } else if (!commands.every(c => c.exit_code === 0)) {
    snapshotStatus = "partial";
  }

  return {
    json: {

      metadata: {
        snapshot_id: `${Date.now()}-${randomInt(1000,9999)}`,
        snapshot_timestamp: new Date().toISOString(),
        collector: "n8n",
        schema_version: "1.2",
        parser_version: "core_collectors_v1"
      },

      snapshot: {

        identity: {
          hostname: hostname,
          host_id: hostId
        },

        system: {
          os_info: osInfo
        },

        network: network,

        status: snapshotStatus
      },

      raw_commands: rawCommands
    }
  };

});

const data = $json;

// ====== Extraemos datos ======
const snapshotId = data.metadata?.snapshot_id || '';
const timestamp = data.metadata?.snapshot_timestamp || '';
const collector = data.metadata?.collector || '';
const status = data.snapshot?.status || '';

const hostname = data.snapshot?.identity?.hostname || '';
const hostId = data.snapshot?.identity?.host_id || '';
const osInfo = data.snapshot?.system?.os_info || '';

const ips = (data.snapshot?.network?.ips || []).join(', ');

const rawHostname = data.raw_commands?.hostname?.stdout || '';
const rawUname = data.raw_commands?.uname?.stdout || '';

// ====== HTML ======
const htmlContent = `
<!DOCTYPE html>
<html>
<head>
<meta charset="utf-8"/>
<style>
body {
  font-family: Arial, sans-serif;
  font-size: 13px;
  margin: 40px;
}

h1 {
  text-align: center;
  margin-bottom: 30px;
}

h2 {
  margin-top: 30px;
}

table {
  border-collapse: collapse;
  width: 100%;
  margin-top: 10px;
}

th, td {
  border: 1px solid #333;
  padding: 8px;
  text-align: left;
  vertical-align: top;
}

th {
  background-color: #f2f2f2;
  width: 25%;
}

.section {
  margin-top: 25px;
}
</style>
</head>
<body>

<h1>Reporte Snapshot</h1>

<div class="section">
<h2>Metadata</h2>
<table>
<tr><th>Snapshot ID</th><td>${snapshotId}</td></tr>
<tr><th>Timestamp</th><td>${timestamp}</td></tr>
<tr><th>Collector</th><td>${collector}</td></tr>
<tr><th>Status</th><td>${status}</td></tr>
</table>
</div>

<div class="section">
<h2>System Info</h2>
<table>
<tr><th>Hostname</th><td>${hostname}</td></tr>
<tr><th>Host ID</th><td>${hostId}</td></tr>
<tr><th>OS Info</th><td>${osInfo}</td></tr>
<tr><th>IP Addresses</th><td>${ips}</td></tr>
</table>
</div>

<div class="section">
<h2>Raw Commands</h2>
<table>
<tr><th>hostname</th><td>${rawHostname}</td></tr>
<tr><th>uname -a</th><td>${rawUname}</td></tr>
</table>
</div>

</body>
</html>
`;

return [
  {
    json: {
      html_base64: Buffer.from(htmlContent).toString('base64')
    }
  }
];
